// Classic Builder — Meal with fluent API
// All fields via setters, validation in build()

class Meal {
    private final String bun;
    private final int patties;
    private final String cheese;
    private final String sauce;
    private final String size;
    private final double price;

    private Meal(Builder builder) {
        this.bun = builder.bun;
        this.patties = builder.patties;
        this.cheese = builder.cheese;
        this.sauce = builder.sauce;
        this.size = builder.size;
        this.price = builder.price;
    }

    @Override
    public String toString() {
        return "[MEAL] " + bun + ", " + patties + " patties, "
            + cheese + " cheese, " + sauce + " sauce, "
            + size + " -- $" + String.format("%.2f", price);
    }

    public static class Builder {
        private String bun;
        private int patties;
        private String cheese;
        private String sauce;
        private String size;
        private double price;

        public Builder setBun(String bun) { this.bun = bun; return this; }
        public Builder setPatties(int patties) { this.patties = patties; return this; }
        public Builder setCheese(String cheese) { this.cheese = cheese; return this; }
        public Builder setSauce(String sauce) { this.sauce = sauce; return this; }
        public Builder setSize(String size) { this.size = size; return this; }
        public Builder setPrice(double price) { this.price = price; return this; }

        public Meal build() {
            if (bun == null || bun.isEmpty())
                throw new IllegalStateException("Bun is required");
            if (patties < 1)
                throw new IllegalStateException("At least 1 patty required");
            if (size == null || size.isEmpty())
                throw new IllegalStateException("Size is required");
            if (price <= 0)
                throw new IllegalStateException("Price must be positive");
            return new Meal(this);
        }
    }
}

public class Main {
    public static void main(String[] args) {
        // Test 1: Build a complete meal
        Meal burger = new Meal.Builder()
            .setBun("Sesame bun")
            .setPatties(2)
            .setCheese("Cheddar")
            .setSauce("BBQ")
            .setSize("Large")
            .setPrice(11.50)
            .build();
        System.out.println(burger);

        // Test 2: Build a minimal meal
        Meal simple = new Meal.Builder()
            .setBun("Plain bun")
            .setPatties(1)
            .setCheese("None")
            .setSauce("Ketchup")
            .setSize("Small")
            .setPrice(5.99)
            .build();
        System.out.println(simple);

        // Test 3: Validation catches missing fields
        try {
            new Meal.Builder().setPatties(1).build();
            System.out.println("ERROR: Should have thrown!");
        } catch (IllegalStateException e) {
            System.out.println("[VALIDATION] " + e.getMessage());
        }

        System.out.println("ALL TESTS PASSED");
    }
}

