// Classic Builder — Meal with fluent API (C++)
#include <iostream>
#include <string>
#include <stdexcept>
#include <iomanip>
#include <sstream>

class Meal {
    std::string bun;
    int patties;
    std::string cheese;
    std::string sauce;
    std::string size;
    double price;

    Meal(std::string b, int p, std::string c, std::string s, std::string sz, double pr)
        : bun(b), patties(p), cheese(c), sauce(s), size(sz), price(pr) {}

public:
    class Builder;
    friend class Builder;

    friend std::ostream& operator<<(std::ostream& os, const Meal& m) {
        std::ostringstream oss;
        oss << std::fixed << std::setprecision(2) << m.price;
        os << "[MEAL] " << m.bun << ", " << m.patties << " patties, "
           << m.cheese << " cheese, " << m.sauce << " sauce, "
           << m.size << " -- $" << oss.str();
        return os;
    }
};

class Meal::Builder {
    std::string bun_;
    int patties_ = 0;
    std::string cheese_;
    std::string sauce_;
    std::string size_;
    double price_ = 0;

public:
    Builder& setBun(const std::string& b) { bun_ = b; return *this; }
    Builder& setPatties(int p) { patties_ = p; return *this; }
    Builder& setCheese(const std::string& c) { cheese_ = c; return *this; }
    Builder& setSauce(const std::string& s) { sauce_ = s; return *this; }
    Builder& setSize(const std::string& s) { size_ = s; return *this; }
    Builder& setPrice(double p) { price_ = p; return *this; }

    Meal build() {
        if (bun_.empty()) throw std::invalid_argument("Bun is required");
        if (patties_ < 1) throw std::invalid_argument("At least 1 patty required");
        if (size_.empty()) throw std::invalid_argument("Size is required");
        if (price_ <= 0) throw std::invalid_argument("Price must be positive");
        return Meal(bun_, patties_, cheese_, sauce_, size_, price_);
    }
};

int main() {
    Meal burger = Meal::Builder()
        .setBun("Sesame bun")
        .setPatties(2)
        .setCheese("Cheddar")
        .setSauce("BBQ")
        .setSize("Large")
        .setPrice(11.50)
        .build();
    std::cout << burger << std::endl;

    Meal simple = Meal::Builder()
        .setBun("Plain bun")
        .setPatties(1)
        .setCheese("None")
        .setSauce("Ketchup")
        .setSize("Small")
        .setPrice(5.99)
        .build();
    std::cout << simple << std::endl;

    try {
        Meal::Builder().setPatties(1).build();
        std::cout << "ERROR: Should have thrown!" << std::endl;
    } catch (const std::invalid_argument& e) {
        std::cout << "[VALIDATION] " << e.what() << std::endl;
    }

    std::cout << "ALL TESTS PASSED" << std::endl;
    return 0;
}

