    private final int patties;
    private final String cheese;
    private final String sauce;
    private final String size;

    private Meal(Builder builder) {
        this.bun = builder.bun;
        this.patties = builder.patties;
        this.cheese = builder.cheese;
        this.sauce = builder.sauce;
        this.size = builder.size;
    }

    @Override
    public String toString() {
        return bun + ", " + patties + " patty, " + cheese + " cheese, " + sauce + " sauce, " + size;
    }

    public static class Builder {
        private String bun;
        private int patties;
        private String cheese;
        private String sauce;
        private String size;

        public Builder setBun(String bun) { this.bun = bun; return this; }
        public Builder setPatties(int patties) { this.patties = patties; return this; }
        public Builder setCheese(String cheese) { this.cheese = cheese; return this; }
        public Builder setSauce(String sauce) { this.sauce = sauce; return this; }
        public Builder setSize(String size) { this.size = size; return this; }

        public Meal build() {
            if (bun == null) throw new IllegalStateException("Bun is required");
            if (patties < 1) throw new IllegalStateException("At least 1 patty");
            return new Meal(this);
        }
    }
}

// Director -- knows recipes, delegates construction to Builder
class MealRecipes {
    public static Meal kidsMeal() {
        return new Meal.Builder()
            .setBun("Small-regular bun")
            .setPatties(1)
            .setCheese("American")
            .setSauce("Ketchup")
            .setSize("Small")
            .build();
    }

    public static Meal gourmetBurger() {
        return new Meal.Builder()
            .setBun("Brioche bun")
            .setPatties(2)
            .setCheese("Gruyere")
            .setSauce("Truffle aioli")
            .setSize("Large")
            .build();
    }

    public static Meal veggieWrap() {
        return new Meal.Builder()
            .setBun("Lettuce wrap")
            .setPatties(1)
            .setCheese("None")
            .setSauce("Ranch")
            .setSize("Medium")
            .build();
    }
}

public class Main {
    public static void main(String[] args) {
        // Test 1: Kids meal via director
        Meal kids = MealRecipes.kidsMeal();
        System.out.println("[KIDS] " + kids);

        // Test 2: Gourmet burger via director
        Meal gourmet = MealRecipes.gourmetBurger();
        System.out.println("[GOURMET] " + gourmet);

        // Test 3: Veggie wrap via director
        Meal veggie = MealRecipes.veggieWrap();
        System.out.println("[VEGGIE] " + veggie);

        // Test 4: Custom build (bypass director)
        Meal custom = new Meal.Builder()
            .setBun("Pretzel bun")
            .setPatties(3)
            .setCheese("Pepper jack")
            .setSauce("Chipotle")
            .setSize("XL")
            .build();
        System.out.println("[CUSTOM] " + custom);

        System.out.println("DIRECTOR TESTS PASSED");
    }
}

